import type { Unit } from '@dynatrace-sdk/units';

import { getCategoricalColoredNodes } from './get-categorical-colored-nodes.js';
import { getCategoricalLegendColorMap } from './get-categorical-legend-color-map.js';
import {
  ColorPalette,
  CustomColorPalette,
} from '../../core/types/color-palette.js';
import type { ColorRuleProps } from '../../core/types/color-rule.js';
import { DEFAULT_ROOT_NODE_NAME } from '../constants.js';
import {
  type ColoredInternalTreeMapData,
  type InternalTreeMapNode,
} from '../types/internal.js';
import { type NameAccessor } from '../types/treemap.js';

/**
 * Function to map the consumer dataset to the internal one that is sorted, colored.
 * Creates the mapping between internal data and the legend items/colors
 * @param tree - treemap root node
 * @param unit - tree data unit
 * @param colorPalette - applied color palette
 * @param nameAccessor - targeted property on the leaf node
 * @param colorRules - raw color rules to apply
 * @returns - InternalTreemapData and Coloring map
 */
export function getColoredInternalCategoricalData(
  tree: InternalTreeMapNode,
  colorPalette: ColorPalette | CustomColorPalette,
  nameAccessor: NameAccessor | undefined,
  colorRules: ColorRuleProps[],
  unit?: string | Unit,
): ColoredInternalTreeMapData {
  const legendColorMap = getCategoricalLegendColorMap(
    tree,
    colorPalette,
    nameAccessor,
    colorRules,
  );

  const nodeArray = getCategoricalColoredNodes(
    tree,
    legendColorMap,
    nameAccessor,
    colorRules,
  );

  const rootNodeName = tree.name ?? DEFAULT_ROOT_NODE_NAME;

  const data = {
    tree: {
      ...tree,
      children: nodeArray,
      name: rootNodeName,
      id: DEFAULT_ROOT_NODE_NAME,
    },
    unit,
  };

  return { data, legendColorMap };
}
